return (async () => {
const raw = $input.item.json;
let chatId, text, isCallback, callbackData, callbackQueryId;

if (raw.callback_query) {
  chatId = raw.callback_query.from.id;
  callbackData = raw.callback_query.data;
  callbackQueryId = raw.callback_query.id;
  isCallback = true;
  text = null;
} else if (raw.message) {
  chatId = raw.message.chat.id;
  text = (raw.message.text || '').trim();
  isCallback = false;
} else {
  return [{ json: { action: 'ignore' } }];
}

const sd = $getWorkflowStaticData('global');
if (!sd.users) sd.users = {};
const uid = String(chatId);
if (!sd.users[uid]) {
  sd.users[uid] = {
    personas_default: null, vetos: [], sustituciones: {},
    estado: null, estado_data: null, lista_id: null,
    listas: {}, pending_recipe: null, historial: []
  };
}
const user = sd.users[uid];
if (!user.historial) user.historial = [];

async function getBaseUrl() {
  try {
    const botToken = $env.BOT_TOKEN || '';
    const res = await fetch('https://api.telegram.org/bot' + botToken + '/getWebhookInfo');
    const data = await res.json();
    const url = data.result?.url || '';
    return url.replace('/webhook/bot-recetas-main/webhook', '');
  } catch(e) { return ''; }
}

let response = null;
let replyMarkup = null;
let answerCallbackId = callbackQueryId || null;

if (isCallback) {
  const pending = user.pending_recipe;
  if (callbackData === 'add_recipe' && pending) {
    if (!user.lista_id) user.lista_id = Math.random().toString(36).substr(2, 9);
    if (!user.listas[user.lista_id]) user.listas[user.lista_id] = { recetas: [] };
    user.listas[user.lista_id].recetas.push(pending);
    // Guardar en historial
    const yaEnHistorial = user.historial.findIndex(h => h.nombre === pending.receta);
    if (yaEnHistorial === -1) {
      user.historial.push({ nombre: pending.receta, fecha: new Date().toLocaleDateString('es-ES') });
      if (user.historial.length > 20) user.historial.shift();
    }
    user.pending_recipe = null;
    const baseUrl = await getBaseUrl();
    const url = baseUrl + '/webhook/lista?id=' + user.lista_id;
    response = '✅ ¡Añadido a tu lista!\n\n🛒 *Lista de la compra:*\n' + url + '\n\nPuedes añadir más recetas cuando quieras.';
  } else if (callbackData === 'skip_recipe') {
    user.pending_recipe = null;
    response = 'De acuerdo 😊 Dime otra receta cuando quieras.';
  } else {
    response = 'No encontré la receta pendiente. Pide la receta de nuevo.';
  }
}
else if (text === '/start' || text === '/help') {
  response = '👋 ¡Hola! Soy tu asistente de recetas y lista de la compra.\n\n*Cómo funciona:*\n1️⃣ Dime para cuántas personas cocinas\n2️⃣ Pídeme una receta (_pollo con almendras_)\n3️⃣ Confirma si añadirla a la lista\n4️⃣ Abre el link para ir marcando en el supermercado\n\n*Comandos:*\n/compartir — link de tu lista para compartir\n/historial — ver y repetir recetas pasadas\n/limpiar — vaciar la lista entera\n/sustitucion — sustituir un ingrediente\n/vetar — vetar un ingrediente\n/perfil — ver tus preferencias\n/reset — cambiar nº de personas\n/nueva — empezar lista nueva\n/eliminar [receta] — quitar receta de la lista\n\n💡 También puedes pedir recetas _para N personas_: _paella para 6_';
}
else if (text === '/compartir') {
  if (!user.lista_id || !user.listas[user.lista_id]?.recetas?.length) {
    response = '📭 Tu lista está vacía. Añade una receta primero.';
  } else {
    const baseUrl = await getBaseUrl();
    const url = baseUrl + '/webhook/lista?id=' + user.lista_id;
    const recetas = user.listas[user.lista_id].recetas.map(r => '• ' + r.receta).join('\n');
    response = '🛒 *Tu lista de la compra:*\n' + url + '\n\n*Recetas en la lista:*\n' + recetas + '\n\nComparte este link con quien quieras para que puedan marcar ingredientes.';
  }
}
else if (text === '/historial') {
  if (!user.historial.length) {
    response = '📖 Todavía no has añadido ninguna receta.\n\nPídeme una receta para empezar.';
  } else {
    const lines = user.historial.slice().reverse().slice(0, 10)
      .map((r, i) => (i+1) + '. ' + r.nombre + ' (' + r.fecha + ')').join('\n');
    response = '📖 *Tus últimas recetas:*\n\n' + lines + '\n\nEscribe */historial N* para volver a pedir la número N.';
  }
}
else if (text && /^\/historial\s+\d+$/.test(text)) {
  const num = parseInt(text.split(/\s+/)[1]);
  const reversed = user.historial.slice().reverse();
  if (num < 1 || num > reversed.length) {
    response = 'Número fuera de rango. Usa /historial para ver la lista.';
  } else {
    const rec = reversed[num - 1];
    const personas = user.personas_default || 2;
    return [{ json: { action: 'recipe_request', chatId, uid, receta: rec.nombre, personas, vetos: user.vetos, sustituciones: user.sustituciones } }];
  }
}
else if (text === '/limpiar') {
  if (!user.lista_id || !user.listas[user.lista_id]?.recetas?.length) {
    response = '📭 Tu lista ya está vacía.';
  } else {
    const count = user.listas[user.lista_id].recetas.length;
    user.listas[user.lista_id] = { recetas: [] };
    response = '🗑 Lista limpiada. Se eliminaron *' + count + ' receta' + (count !== 1 ? 's' : '') + '*.\n\nDime qué quieres cocinar.';
  }
}
else if (text === '/sustitucion') {
  user.estado = 'esperando_ingrediente';
  response = '🔄 ¿Qué ingrediente NO quieres en tus recetas?';
}
else if (text && text.startsWith('/vetar')) {
  const ing = text.replace('/vetar', '').trim().toLowerCase();
  if (!ing) { response = 'Usa: /vetar pimiento'; }
  else {
    if (!user.vetos.includes(ing)) user.vetos.push(ing);
    response = '🚫 *' + ing + '* vetado.\n\nVe tus preferencias con /perfil';
  }
}
else if (text === '/perfil') {
  const v = user.vetos.length ? user.vetos.map(x => '• ' + x).join('\n') : '• ninguno';
  const s = Object.keys(user.sustituciones).length
    ? Object.entries(user.sustituciones).map(([k, val]) => '• ' + k + ' → ' + val).join('\n') : '• ninguna';
  const lista = user.lista_id && user.listas[user.lista_id]
    ? user.listas[user.lista_id].recetas.map(r => '• ' + r.receta).join('\n') || '• (vacía)' : '• (vacía)';
  const hist = user.historial.length ? user.historial.slice(-5).reverse().map(r => '• ' + r.nombre).join('\n') : '• ninguna';
  response = '👤 *Tu perfil*\n\n👥 Personas: ' + (user.personas_default || 'no configurado') + '\n\n🚫 Vetados:\n' + v + '\n\n🔄 Sustituciones:\n' + s + '\n\n📋 Lista actual:\n' + lista + '\n\n📖 Últimas recetas:\n' + hist;
}
else if (text === '/reset') {
  user.personas_default = null;
  response = '🔄 ¿Para cuántas personas ahora?';
}
else if (text === '/nueva') {
  user.lista_id = null;
  user.pending_recipe = null;
  response = '🗑 Lista borrada. Dime qué receta quieres:';
}
else if (text && text.startsWith('/eliminar')) {
  const nombre = text.replace('/eliminar', '').trim();
  if (!nombre) { response = 'Usa: /eliminar carbonara'; }
  else if (!user.lista_id || !user.listas[user.lista_id]?.recetas?.length) { response = 'Tu lista está vacía.'; }
  else {
    const lista = user.listas[user.lista_id];
    const antes = lista.recetas.length;
    lista.recetas = lista.recetas.filter(r => !r.receta.toLowerCase().includes(nombre.toLowerCase()));
    response = lista.recetas.length < antes ? '🗑 Receta eliminada.' : 'No encontré esa receta. Lista: ' + user.listas[user.lista_id].recetas.map(r => r.receta).join(', ');
  }
}
else if (user.estado === 'esperando_ingrediente') {
  user.estado_data = text.toLowerCase().trim();
  user.estado = 'esperando_sustituto';
  response = '¿Con qué sustituimos *' + text + '*?\n(escribe _nada_ para vetarlo directamente)';
}
else if (user.estado === 'esperando_sustituto') {
  const ing = user.estado_data;
  if (text.toLowerCase() === 'nada') {
    if (!user.vetos.includes(ing)) user.vetos.push(ing);
    response = '🚫 *' + ing + '* vetado. Verifica con /perfil';
  } else {
    user.sustituciones[ing] = text.toLowerCase().trim();
    response = '✅ Guardado: *' + ing + '* → *' + text + '*. Verifica con /perfil';
  }
  user.estado = null;
  user.estado_data = null;
}
else if (!user.personas_default) {
  const num = parseInt(text);
  if (!isNaN(num) && num > 0 && num < 100) {
    user.personas_default = num;
    response = '✅ Perfecto, sois *' + num + ' persona' + (num===1?'':'s') + '*.\n\nDime qué receta quieres hacer 🍽';
  } else {
    response = '👋 ¡Hola! Soy tu asistente de recetas.\n\n¿Para cuántas personas quieres las listas de la compra?';
  }
}
else {
  const match = text.match(/\bpara\s+(\d+)\b/i);
  const personasOverride = match ? parseInt(match[1]) : null;
  const recetaLimpia = text.replace(/\bpara\s+\d+\s*personas?\b/i, '').trim();
  const personas = personasOverride || user.personas_default;
  return [{ json: { action: 'recipe_request', chatId, uid, receta: recetaLimpia, personas, vetos: user.vetos, sustituciones: user.sustituciones } }];
}

return [{ json: { action: 'send_message', chatId, text: response, replyMarkup, answerCallbackId } }];
})();

const ctx = $input.item.json;
const { receta, personas, vetos, sustituciones } = ctx;
const vetosStr = vetos.length ? vetos.join(', ') : 'ninguno';
const sustStr = Object.keys(sustituciones).length
  ? Object.entries(sustituciones).map(([k,v]) => `${k} → ${v}`).join(', ')
  : 'ninguna';

const systemPrompt = `Eres un chef experto. Genera recetas con ingredientes y cantidades precisas.\n\nContexto:\n- Personas: ${personas}\n- Ingredientes VETADOS: ${vetosStr}\n- Sustituciones: ${sustStr}\n\nResponde ÚNICAMENTE con JSON válido sin texto adicional:\n{\n  "nombre": "nombre receta",\n  "esVetada": false,\n  "motivoVeto": null,\n  "ingredientes": [{"nombre": "", "cantidad": 0, "unidad": "", "sustituido": false, "original": null}],\n  "preparacion": "2-3 frases"\n}\n\nReglas:\n1. Escala cantidades para ${personas} personas\n2. Si vetado es ESENCIAL: esVetada:true, explica en motivoVeto\n3. Si hay sustitución: usa el sustituto, sustituido:true, original con nombre original\n4. Vetado secundario: simplemente omítelo\n5. cantidad:null si es al gusto`;

const apiKey = $env.OPENROUTER_API_KEY || '';

const requestBodyStr = JSON.stringify({
  model: 'openai/gpt-oss-20b:free',
  messages: [
    { role: 'system', content: systemPrompt },
    { role: 'user', content: 'Genera la receta de: "' + receta + '"' }
  ],
  temperature: 0.2,
  max_tokens: 1500
});

return [{ json: { ...ctx, requestBodyStr, apiKey } }];

const deepseekData = $input.item.json;
const ctx = $('Preparar Prompt').item.json;
const { chatId, uid, receta, personas } = ctx;

const content = deepseekData.choices?.[0]?.message?.content || '';
let recipe;
try {
  const match = content.match(/```(?:json)?\n?([\s\S]*?)\n?```/) || [null, content];
  recipe = JSON.parse(match[1].trim());
} catch(e) {
  return [{ json: { action: 'send_message', chatId, text: `❌ No encontré la receta de _${receta}_.\n\nIntenta con un nombre más concreto.`, replyMarkup: null, answerCallbackId: null } }];
}

if (recipe.esVetada) {
  return [{ json: { action: 'send_message', chatId, text: `🚫 *${recipe.nombre}* no es posible con tus preferencias.\n\n_${recipe.motivoVeto}_\n\nPrueba con otra receta o revisa tus vetos con /perfil`, replyMarkup: null, answerCallbackId: null } }];
}

const ingredientes = (recipe.ingredientes || []).map((ing, i) => ({
  id: `ing_${Date.now()}_${i}`,
  nombre: ing.nombre,
  cantidad: ing.cantidad,
  unidad: ing.unidad || null,
  checked: false,
  sustituido: ing.sustituido || false,
  original: ing.original || null
}));

const sd = $getWorkflowStaticData('global');
if (!sd.users) sd.users = {};
if (!sd.users[uid]) sd.users[uid] = {};
sd.users[uid].pending_recipe = {
  id: `rec_${Date.now()}`,
  receta: recipe.nombre,
  personas,
  ingredientes
};

const ingLines = ingredientes.map(ing => {
  const qty = ing.cantidad != null ? `${ing.cantidad}${ing.unidad ? ' '+ing.unidad : ''}` : '';
  const sub = ing.sustituido ? ` _(↔ ${ing.original})_` : '';
  return `• ${ing.nombre}${qty ? ' — '+qty : ''}${sub}`;
}).join('\n');

const msgText = `🍽 *${recipe.nombre}* — para ${personas} persona${personas!==1?'s':''}\n\n📋 *Ingredientes:*\n${ingLines}\n\n📝 *Preparación:*\n${recipe.preparacion}\n\n¿Añado los ingredientes a la lista de la compra?`;

const botToken = $env.TELEGRAM_BOT_TOKEN || '';
return [{ json: {
  action: 'send_recipe', chatId, botToken,
  text: msgText,
  replyMarkup: JSON.stringify({ inline_keyboard: [[{ text: '✅ Añadir a la lista', callback_data: 'add_recipe' }, { text: '❌ No añadir', callback_data: 'skip_recipe' }]] }),
  answerCallbackId: null
} }];

const listId = $input.item.json.query?.id || '';
const botUser = ($env.BOT_USERNAME || 'tu_bot').replace(/@/g,'');

const sd = $getWorkflowStaticData('global');
let listaData = { recetas: [] };
if (listId) {
  for (const uid of Object.keys(sd.users || {})) {
    const user = sd.users[uid];
    if (user.lista_id === listId && user.listas && user.listas[listId]) {
      listaData = user.listas[listId];
      break;
    }
  }
}

const dataScript = 'const LID=' + JSON.stringify(listId) + ';const BOT=' + JSON.stringify(botUser) + ';const API=location.origin;let data=' + JSON.stringify(listaData) + ';';

const css = `*{box-sizing:border-box;margin:0;padding:0}body{font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;background:#f0f2f5;color:#1a1a1a}.header{background:linear-gradient(135deg,#1976D2,#42A5F5);color:white;padding:16px 20px;position:sticky;top:0;z-index:100;box-shadow:0 2px 8px rgba(0,0,0,.2)}.header h1{font-size:20px;font-weight:700}.header-sub{font-size:12px;opacity:.85;margin-top:3px}.prog-bar{background:rgba(255,255,255,.3);border-radius:10px;height:4px;margin-top:8px}.prog-fill{background:white;height:100%;border-radius:10px;transition:width .4s}.tabs{display:flex;background:white;box-shadow:0 1px 0 #e0e0e0}.tab{flex:1;padding:13px 0;text-align:center;cursor:pointer;font-size:14px;font-weight:500;color:#666;border-bottom:3px solid transparent}.tab.active{color:#1976D2;border-bottom-color:#1976D2}.content{padding:16px;max-width:640px;margin:0 auto}.card{background:white;border-radius:14px;margin-bottom:14px;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,.08)}.card-header{padding:14px 16px;display:flex;align-items:center;justify-content:space-between;cursor:pointer}.card-title{font-weight:700;font-size:16px}.card-meta{font-size:12px;color:#888;margin-top:2px}.card-right{display:flex;align-items:center;gap:8px}.badge{font-size:13px;color:#1976D2;font-weight:600;background:#E3F2FD;padding:3px 8px;border-radius:12px}.btn-del{background:none;border:none;cursor:pointer;color:#e53935;font-size:17px;padding:4px 6px}.chevron{font-size:12px;color:#bbb;transition:transform .25s}.collapsed .chevron{transform:rotate(-90deg)}.collapsed .card-body{display:none}.prog-card{background:#f0f0f0;height:3px}.prog-card-fill{background:#4CAF50;height:100%;transition:width .4s}.items{border-top:1px solid #f5f5f5}.item{display:flex;align-items:center;padding:11px 16px;border-bottom:1px solid #fafafa;gap:12px}.item input{width:20px;height:20px;cursor:pointer;accent-color:#1976D2;flex-shrink:0}.iname{flex:1;font-size:15px}.iname.done{text-decoration:line-through;color:#bbb}.isub{font-size:11px;color:#FF7043;margin-top:1px}.iqty{font-size:13px;color:#999;white-space:nowrap;font-weight:500}.sec-label{font-size:11px;text-transform:uppercase;letter-spacing:.8px;font-weight:700;color:#999;padding:16px 4px 8px}.empty{text-align:center;padding:60px 24px}.add-btn{display:flex;align-items:center;justify-content:center;background:#1976D2;color:white;border:none;padding:15px 24px;border-radius:28px;font-size:15px;font-weight:600;cursor:pointer;width:100%;margin-top:8px;margin-bottom:24px}.toast{position:fixed;bottom:24px;left:50%;transform:translateX(-50%);background:#323232;color:white;padding:10px 22px;border-radius:22px;font-size:14px;opacity:0;pointer-events:none;transition:opacity .25s;z-index:999}`;

const js = `
let activeTab='r';
function tab(t){
  activeTab=t;
  document.getElementById('tr').classList.toggle('active',t==='r');
  document.getElementById('tc').classList.toggle('active',t==='c');
  document.getElementById('vr').style.display=t==='r'?'':'none';
  document.getElementById('vc').style.display=t==='c'?'':'none';
}
function esc(s){return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');}
function fqty(i){
  if(!i.cantidad&&!i.unidad)return '';
  var q=i.cantidad!=null?(Number.isInteger(i.cantidad)?i.cantidad:parseFloat(i.cantidad.toFixed(1))):'';
  return (q+' '+(i.unidad||'')).trim();
}
function toast(m){
  var el=document.getElementById('toast');
  el.textContent=m;el.style.opacity=1;
  setTimeout(function(){el.style.opacity=0;},2000);
}
function render(){
  var rs=data.recetas||[];
  var tot=rs.reduce(function(s,r){return s+r.ingredientes.length;},0);
  var don=rs.reduce(function(s,r){return s+r.ingredientes.filter(function(i){return i.checked;}).length;},0);
  var pct=tot>0?Math.round(don/tot*100):0;
  document.getElementById('hsub').textContent=rs.length+' receta'+(rs.length!==1?'s':'')+' - '+tot+' ingrediente'+(tot!==1?'s':'')+(tot>0?' - '+don+'/'+tot+' en carro':'');
  document.getElementById('hprog').style.width=pct+'%';
  renderR(rs);renderC(rs);
}
function addBtn(container){
  var btn=document.createElement('button');
  btn.className='add-btn';btn.textContent='+ Añadir otra receta';
  btn.addEventListener('click',function(){window.open('https://t.me/'+BOT,'_blank');});
  container.appendChild(btn);
}
function renderR(rs){
  var el=document.getElementById('vr');
  el.innerHTML='';
  if(!rs.length){
    el.innerHTML='<div class="empty"><div style="font-size:48px">🍽</div><p>Lista vacía</p></div>';
    return;
  }
  rs.forEach(function(rec){
    var tot=rec.ingredientes.length;
    var chk=rec.ingredientes.filter(function(i){return i.checked;}).length;
    var pct=tot>0?chk/tot*100:0;
    var card=document.createElement('div');
    card.className='card';card.id='card-'+rec.id;
    var hdr=document.createElement('div');hdr.className='card-header';
    hdr.innerHTML='<div><div class="card-title">'+esc(rec.receta)+'</div><div class="card-meta">Para '+rec.personas+' persona'+(rec.personas!==1?'s':'')+'</div></div>'
      +'<div class="card-right"><span class="badge">'+chk+'/'+tot+'</span>'
      +'<button class="btn-del" title="Eliminar">🗑</button><span class="chevron">▼</span></div>';
    hdr.querySelector('.btn-del').addEventListener('click',function(e){
      e.stopPropagation();
      if(!confirm('¿Eliminar esta receta?'))return;
      data.recetas=data.recetas.filter(function(r){return r.id!==rec.id;});
      render();toast('Receta eliminada');
      fetch(API+'/webhook/lista-eliminar',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({listId:LID,recipeId:rec.id})}).catch(function(){});
    });
    hdr.addEventListener('click',function(){card.classList.toggle('collapsed');});
    card.appendChild(hdr);
    var prog=document.createElement('div');prog.className='prog-card';
    prog.innerHTML='<div class="prog-card-fill" style="width:'+pct+'%"></div>';
    card.appendChild(prog);
    var body=document.createElement('div');body.className='card-body';
    var items=document.createElement('div');items.className='items';
    rec.ingredientes.forEach(function(ing){
      var row=document.createElement('div');row.className='item';
      var cb=document.createElement('input');cb.type='checkbox';cb.id='c-'+ing.id;cb.checked=ing.checked;
      cb.addEventListener('change',function(){
        ing.checked=cb.checked;
        render();toast(cb.checked?'En el carro':'Quitado');
        fetch(API+'/webhook/lista-toggle',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({listId:LID,recipeId:rec.id,ingId:ing.id,checked:cb.checked})}).catch(function(){});
      });
      var lbl=document.createElement('label');lbl.htmlFor='c-'+ing.id;lbl.style.flex='1';lbl.style.cursor='pointer';
      var nm=document.createElement('div');nm.className='iname'+(ing.checked?' done':'');nm.textContent=ing.nombre;
      lbl.appendChild(nm);
      if(ing.sustituido){var sub=document.createElement('div');sub.className='isub';sub.textContent='sustituido de '+ing.original;lbl.appendChild(sub);}
      var qty=document.createElement('span');qty.className='iqty';qty.textContent=fqty(ing);
      row.appendChild(cb);row.appendChild(lbl);row.appendChild(qty);
      items.appendChild(row);
    });
    body.appendChild(items);card.appendChild(body);
    el.appendChild(card);
  });
  addBtn(el);
}
function renderC(rs){
  var el=document.getElementById('vc');el.innerHTML='';
  if(!rs.length){el.innerHTML='<div class="empty"><div style="font-size:48px">📋</div><p>Sin ingredientes</p></div>';return;}
  var map={};
  rs.forEach(function(rec){
    rec.ingredientes.forEach(function(ing){
      var key=ing.nombre.trim().toLowerCase();
      if(map[key]){
        map[key].recetas.push(rec.receta);
        if(ing.unidad&&map[key].unidad===ing.unidad&&ing.cantidad!=null)map[key].cantidad=(parseFloat(map[key].cantidad)||0)+parseFloat(ing.cantidad);
        if(!ing.checked)map[key].checked=false;
        map[key].refs.push({rId:rec.id,iId:ing.id});
      } else {
        map[key]={nombre:ing.nombre,cantidad:ing.cantidad,unidad:ing.unidad,checked:ing.checked,recetas:[rec.receta],refs:[{rId:rec.id,iId:ing.id}]};
      }
    });
  });
  var all=Object.values(map);
  var pend=all.filter(function(i){return !i.checked;});
  var done=all.filter(function(i){return i.checked;});
  function mkRow(ing){
    var row=document.createElement('div');row.className='item';
    var cbId='cons-'+ing.nombre.toLowerCase().replace(/\s+/g,'-');
    var cb=document.createElement('input');cb.type='checkbox';cb.id=cbId;cb.checked=ing.checked;
    cb.addEventListener('change',function(){
      var refs=ing.refs;
      refs.forEach(function(r){
        var rec=data.recetas.find(function(x){return x.id===r.rId;});
        if(rec){var i=rec.ingredientes.find(function(x){return x.id===r.iId;});if(i)i.checked=cb.checked;}
      });
      render();toast(cb.checked?'En el carro':'Quitado');
      refs.forEach(function(r){fetch(API+'/webhook/lista-toggle',{method:'POST',headers:{'Content-Type':'application/json'},body:JSON.stringify({listId:LID,recipeId:r.rId,ingId:r.iId,checked:cb.checked})}).catch(function(){});});
    });
    var lbl=document.createElement('label');lbl.htmlFor=cbId;lbl.style.flex='1';lbl.style.cursor='pointer';
    var nm=document.createElement('div');nm.className='iname'+(ing.checked?' done':'');nm.textContent=ing.nombre;
    var meta=document.createElement('div');meta.style.fontSize='11px';meta.style.color='#999';meta.textContent=ing.recetas.join(' - ');
    lbl.appendChild(nm);lbl.appendChild(meta);
    var qty=document.createElement('span');qty.className='iqty';qty.textContent=fqty(ing);
    row.appendChild(cb);row.appendChild(lbl);row.appendChild(qty);
    return row;
  }
  if(pend.length){var card=document.createElement('div');card.className='card';var items=document.createElement('div');items.className='items';pend.forEach(function(i){items.appendChild(mkRow(i));});card.appendChild(items);el.appendChild(card);}
  if(done.length){var lbl2=document.createElement('div');lbl2.className='sec-label';lbl2.textContent='Ya en el carro';el.appendChild(lbl2);var card2=document.createElement('div');card2.className='card';card2.style.opacity='.6';var items2=document.createElement('div');items2.className='items';done.forEach(function(i){items2.appendChild(mkRow(i));});card2.appendChild(items2);el.appendChild(card2);}
  addBtn(el);
}
document.querySelectorAll('.tab').forEach(function(t){t.addEventListener('click',function(){tab(t.dataset.tab);});});
render();
`;

